class User(DjangoObjectType):
    class Meta:
        model = 'auth_user'
        fields = ('id', 'username')


class UpdateUserInput(InputType):
    username = graphene.String()
    email = graphene.String()
    bio = graphene.String()
    role = graphene.String()
    is_admin = graphene.Boolean()
    credits = graphene.Int()
    subscription_tier = graphene.String()


class UpdateUser(graphene.Mutation):

    class Arguments:
        input = UpdateUserInput(required=True)

    user = graphene.Field(User, required=True)

    def mutate(root, info, input):

        try:
            user = info.context['user']

            if not user or not user.is_authenticated():
                raise GraphQLError('You must be logged in to update your profile.')

            for key, value in input.__dict__.items():

                if hasattr(user, key) and value is not None:
                    setattr(user, key, value)

            user.save()
            return UpdateUser(user=user)

        except Exception as e:
            raise GraphQLError('Error updating your profile.')


class Mutation(graphene.ObjectType):
    update_user = UpdateUser.Field()